2587 /// Tries to reduce a pattern that arises when calculating the remainder of the
2588 /// Euclidean division. When the divisor is a power of two and is guaranteed not
2589 /// to be negative, a signed remainder can be folded with a bitwise and.
2590 ///
2591 /// (x % n) < 0 ? (x % n) + n : (x % n)
2592 ///    -> x & (n - 1)
2593 static Instruction *foldSelectWithSRem(SelectInst &SI, InstCombinerImpl &IC,
2594                                        IRBuilderBase &Builder) {
2595   Value *CondVal = SI.getCondition();
2596   Value *TrueVal = SI.getTrueValue();
2597   Value *FalseVal = SI.getFalseValue();
2598 
2599   ICmpInst::Predicate Pred;
2600   Value *Op, *RemRes, *Remainder;
2601   const APInt *C;
2602   bool TrueIfSigned = false;
2603 
2604   if (!(match(CondVal, m_ICmp(Pred, m_Value(RemRes), m_APInt(C))) &&
2605         IC.isSignBitCheck(Pred, *C, TrueIfSigned)))
2606     return nullptr;
2607 
2608   // If the sign bit is not set, we have a SGE/SGT comparison, and the operands
2609   // of the select are inverted.
2610   if (!TrueIfSigned)
2611     std::swap(TrueVal, FalseVal);
2612 
2613   // We are matching a quite specific pattern here:
2614   // %rem = srem i32 %x, %n
2615   // %cnd = icmp slt i32 %rem, 0
2616   // %add = add i32 %rem, %n
2617   // %sel = select i1 %cnd, i32 %add, i32 %rem
2618   if (!(match(TrueVal, m_Add(m_Value(RemRes), m_Value(Remainder))) &&
2619         match(RemRes, m_SRem(m_Value(Op), m_Specific(Remainder))) &&
2620         IC.isKnownToBeAPowerOfTwo(Remainder, /*OrZero*/ true) &&
2621         FalseVal == RemRes))
2622     return nullptr;
2623 
2624   Value *Add = Builder.CreateAdd(Remainder,
2625                                  Constant::getAllOnesValue(RemRes->getType()));
2626   return BinaryOperator::CreateAnd(Op, Add);
2627 }
